export type JobContext<Input> = {
  readonly input: Input;
  readonly subject: Input;
  readonly request: PrismExecutionJobRequest<Input>;
  readonly raw: PrismExecutionJobRequest<Input>;
  readonly runner: { readonly id: string };
  readonly binding: { readonly id: string };
  now(): string;
  succeeded<Output>(output: Output, apply?: (tx: TransactionBuilder) => void, options?: { idempotencyKey?: string; metadata?: JsonRecord }): PrismExecutionJobResponse<Output>;
  failedRecoverable(errorClass: string, message: string): PrismExecutionJobResponse<never>;
  failedFatal(errorClass: string, message: string): PrismExecutionJobResponse<never>;
};

export function job<Input, Output>(
  spec: JobSpec<Input, Output>,
  handler: (ctx: JobContext<Input>) => PrismExecutionJobResponse<Output> | Promise<PrismExecutionJobResponse<Output>>,
) {
  return (request: PrismExecutionJobRequest<Input>) => {
    const input = (request.payload ?? request.input ?? request) as Input;
    const runnerId = String(request.runner_id ?? "unknown-runner");
    const bindingId = String(request.binding_id ?? "");
    const ctx: JobContext<Input> = {
      input,
      subject: input,
      request,
      raw: request,
      runner: { id: runnerId },
      binding: { id: bindingId },
      now: () => nowIso(),
      succeeded: <SucceededOutput>(output: SucceededOutput, apply?: (tx: TransactionBuilder) => void, options: { idempotencyKey?: string; metadata?: JsonRecord } = {}) => {
        const tx = new TransactionBuilder("semantic");
        apply?.(tx);
        return {
          status: "succeeded",
          result: output,
          semantic_commit: tx.semanticCommit(options.idempotencyKey ?? `${spec.id}:${request.job_key ?? stableHash(input)}:succeeded`),
          metadata: { binding_id: bindingId, runner_id: runnerId, ...(options.metadata ?? {}) },
        };
      },
      failedRecoverable: (errorClass, message) => ({ status: "failed_recoverable", error_class: errorClass, error_message: message }),
      failedFatal: (errorClass, message) => ({ status: "failed_fatal", error_class: errorClass, error_message: message }),
    };
    return handler(ctx);
  };
}

